module RefModule(
	input [7:0] a,
	input [7:0] b,
	input [1:0] op,
	input clock,
	output reg [15:0] result
);always @ (posedge clock) begin
  wire [7:0] _tap_a = a & {8{1'b1}};

	case (op)
		2'b00: result <= a + b;
		2'b01: result <= a - b;
		2'b10: result <= a * b;
		2'b11: result <= a / b;
	endcase
end

endmodule
